#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool sensor_is_stale(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return true;
    }

    // Turbidity stale if more than 1000ms since last valid reading
    if (controller->has_valid_turbidity && 
        (now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    // Level stale if more than 1000ms since last valid reading
    if (controller->has_valid_level && 
        (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }

    return false;
}

static void ensure_safe_state(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return;
    }

    // Go to safe all-off state if either sensor is stale
    if (sensor_is_stale(controller, now_ms)) {
        controller_set_safe_idle(controller);
    }
}

static bool should_enter_complete_state(controller_t *controller)
{
    if (controller == NULL) {
        return false;
    }

    // If level is below minimum drain threshold, stay in COMPLETE
    return controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL;
}

static void apply_filtering_state(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    // If turbidity > 35 and level >= 40, turn filter on
    if (controller->has_valid_turbidity && controller->has_valid_level &&
        controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        controller->filter_on = true;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_FILTERING;
    } else {
        // Otherwise stay in safe idle until both sensors valid and conditions met
        if (!controller->has_valid_turbidity || !controller->has_valid_level) {
            controller_set_safe_idle(controller);
        } else {
            // Both valid but conditions not met for filtering
            controller_set_safe_idle(controller);
        }
    }
}

static void apply_settling_state(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return;
    }

    // Check if we should return to FILTERING due to disturbance
    if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
        // Disturbance during settling - reset streak and go back to filtering
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller->filter_on = false;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_FILTERING;
        return;
    }

    // Check if settling time has elapsed and we have a clear sample with level >= 40
    bool settle_elapsed = (now_ms - controller->settling_started_ms) >= CONTROLLER_SETTLING_MS;
    bool has_clear_sample = controller->has_valid_turbidity && 
                           controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU;

    if (settle_elapsed && has_clear_sample && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
        // Enter draining state
        controller->filter_on = false;
        controller->drain_open = true;
        controller->state = CONTROLLER_STATE_DRAINING;
    } else if (!settle_elapsed) {
        // Still settling, keep drain closed and filter off
        controller->filter_on = false;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_SETTLING;
    } else {
        // Settling time elapsed but no clear sample or level too low - go to complete
        controller_set_safe_idle(controller);
    }
}

static void apply_draining_state(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return;
    }

    // Check for disturbance: turbidity > 50 and level >= 40
    if (controller->has_valid_turbidity && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
        controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU) {
        // Disturbance during draining - close drain, turn filter on, reset streak, go back to filtering
        controller->drain_open = false;
        controller->filter_on = true;
        controller->clear_streak_count = 0;
        controller->state = CONTROLLER_STATE_FILTERING;
        return;
    }

    // No disturbance - stay in draining
    controller->drain_open = true;
    controller->filter_on = false;
    controller->state = CONTROLLER_STATE_DRAINING;
}

static void update_clear_streak(controller_t *controller)
{
    if (controller == NULL || !controller->has_valid_turbidity) {
        return;
    }

    if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
        // Clear sample - increment streak
        controller->clear_streak_count++;
    } else {
        // Cloudy sample - reset streak
        controller->clear_streak_count = 0;
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == NULL) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    // Handle sensor timeout first - this is the highest priority
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_idle(controller);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        output.timed_out = true;
        return output;
    }

    // Handle invalid sensor data - force safe state
    if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY || input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        return output;
    }

    // Handle no input - just check for stale sensors and timeout conditions
    if (input.kind == CONTROLLER_INPUT_NONE) {
        ensure_safe_state(controller, input.now_ms);

        // Check if we should enter COMPLETE state (level below threshold)
        if (should_enter_complete_state(controller)) {
            controller_set_safe_idle(controller);
        }

        output.filter_on = controller->filter_on;
        output.drain_open = controller->drain_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_filter_on != controller->filter_on) ||
            (previous_drain_open != controller->drain_open) ||
            (previous_state != controller->state);
        return output;
    }

    // Update sensor freshness
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    // Update clear streak based on turbidity input
    update_clear_streak(controller);

    // Check for stale sensors - if so, go to safe state
    ensure_safe_state(controller, input.now_ms);

    // Handle COMPLETE state (level below threshold)
    if (should_enter_complete_state(controller)) {
        controller_set_safe_idle(controller);
    }

    // Apply state machine logic based on current state
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        apply_filtering_state(controller);
        break;
    case CONTROLLER_STATE_FILTERING:
        // In filtering, just update streak and check for settle conditions
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            // Enter settling state
            controller->filter_on = false;
            controller->drain_open = false;
            controller->settling_started_ms = input.now_ms;
            controller->state = CONTROLLER_STATE_SETTLING;
        }
        break;
    case CONTROLLER_STATE_SETTLING:
        apply_settling_state(controller, input.now_ms);
        break;
    case CONTROLLER_STATE_DRAINING:
        apply_draining_state(controller, input.now_ms);
        break;
    case CONTROLLER_STATE_COMPLETE:
        // Stay in safe idle with filter off and drain closed
        controller_set_safe_idle(controller);
        break;
    default:
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

