static bool sensor_is_stale(controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return true;
    }

    // Turbidity stale if more than 1000ms since last valid reading
    if (controller->has_valid_turbidity && 
        (now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
